import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import {
  FileUpload as FileUploadPrimitive,
  useFileUpload,
  useFileUploadContext,
} from '@ark-ui/react/file-upload';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef, ReactElement, ReactNode } from 'react';
import { Children, cloneElement, forwardRef } from 'react';
import { CloseIcon, FileIcon, TrashIcon, UploadIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import { CloseButton } from '../close-button';
import styles from './FileUpload.module.css';

const FileUploadRoot = forwardRef<
  ComponentRef<typeof FileUploadPrimitive.Root>,
  ComponentProps<typeof FileUploadPrimitive.Root>
>(function FileUploadRoot({ asChild, children, className, ...props }, ref) {
  return (
    <FileUploadPrimitive.Root
      ref={ref}
      asChild={asChild}
      data-slot="file-upload-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    >
      {withHiddenInput(children, asChild)}
    </FileUploadPrimitive.Root>
  );
});

const FileUploadRootProvider = forwardRef<
  ComponentRef<typeof FileUploadPrimitive.RootProvider>,
  ComponentProps<typeof FileUploadPrimitive.RootProvider>
>(function FileUploadRootProvider({ asChild, children, className, ...props }, ref) {
  return (
    <FileUploadPrimitive.RootProvider
      ref={ref}
      asChild={asChild}
      data-slot="file-upload-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    >
      {withHiddenInput(children, asChild)}
    </FileUploadPrimitive.RootProvider>
  );
});

const FileUploadLabel = forwardRef<
  ComponentRef<typeof FileUploadPrimitive.Label>,
  ComponentProps<typeof FileUploadPrimitive.Label>
>(function FileUploadLabel({ className, ...props }, ref) {
  return (
    <FileUploadPrimitive.Label
      ref={ref}
      data-slot="file-upload-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const FileUploadDropzone = forwardRef<
  ComponentRef<typeof FileUploadPrimitive.Dropzone>,
  ComponentProps<typeof FileUploadPrimitive.Dropzone>
>(function FileUploadDropzone({ className, ...props }, ref) {
  return (
    <FileUploadPrimitive.Dropzone
      ref={ref}
      data-slot="file-upload-dropzone"
      className={clsx(styles.dropzone, normalizeClassName(className))}
      {...props}
    />
  );
});

function FileUploadDropzoneIcon({ className, children, ...props }: HTMLArkProps<'span'>) {
  return (
    <ark.span
      aria-hidden="true"
      data-slot="file-upload-dropzone-icon"
      className={clsx(styles.dropzoneIcon, normalizeClassName(className))}
      {...props}
    >
      {children ?? <UploadIcon />}
    </ark.span>
  );
}

const FileUploadTrigger = forwardRef<
  ComponentRef<typeof FileUploadPrimitive.Trigger>,
  ComponentProps<typeof FileUploadPrimitive.Trigger>
>(function FileUploadTrigger({ className, ...props }, ref) {
  return (
    <FileUploadPrimitive.Trigger
      ref={ref}
      data-slot="file-upload-trigger"
      className={clsx(styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

function withHiddenInput(children: ReactNode, asChild?: boolean) {
  const hiddenInput = <FileUploadPrimitive.HiddenInput data-slot="file-upload-hidden-input" />;

  if (!asChild) {
    return (
      <>
        {children}
        {hiddenInput}
      </>
    );
  }

  const child = Children.only(children) as ReactElement<{ children?: ReactNode }>;

  return cloneElement(child, {}, child.props.children, hiddenInput);
}

const FileUploadItemGroup = forwardRef<
  ComponentRef<typeof FileUploadPrimitive.ItemGroup>,
  ComponentProps<typeof FileUploadPrimitive.ItemGroup>
>(function FileUploadItemGroup({ className, ...props }, ref) {
  return (
    <FileUploadPrimitive.ItemGroup
      ref={ref}
      data-slot="file-upload-item-group"
      className={clsx(styles.itemGroup, normalizeClassName(className))}
      {...props}
    />
  );
});

const FileUploadItem = forwardRef<
  ComponentRef<typeof FileUploadPrimitive.Item>,
  ComponentProps<typeof FileUploadPrimitive.Item>
>(function FileUploadItem({ className, ...props }, ref) {
  return (
    <FileUploadPrimitive.Item
      ref={ref}
      data-slot="file-upload-item"
      className={clsx(styles.item, normalizeClassName(className))}
      {...props}
    />
  );
});

const FileUploadItemPreview = forwardRef<
  ComponentRef<typeof FileUploadPrimitive.ItemPreview>,
  ComponentProps<typeof FileUploadPrimitive.ItemPreview>
>(function FileUploadItemPreview({ className, ...props }, ref) {
  return (
    <FileUploadPrimitive.ItemPreview
      ref={ref}
      data-slot="file-upload-item-preview"
      className={clsx(styles.itemPreview, normalizeClassName(className))}
      {...props}
    />
  );
});

const FileUploadItemPreviewImage = forwardRef<
  ComponentRef<typeof FileUploadPrimitive.ItemPreviewImage>,
  ComponentProps<typeof FileUploadPrimitive.ItemPreviewImage>
>(function FileUploadItemPreviewImage({ className, ...props }, ref) {
  return (
    <FileUploadPrimitive.ItemPreviewImage
      ref={ref}
      data-slot="file-upload-item-preview-image"
      className={clsx(styles.itemPreviewImage, normalizeClassName(className))}
      {...props}
    />
  );
});

function FileUploadItemPreviewIcon({ className, ...props }: ComponentProps<typeof FileIcon>) {
  return (
    <FileIcon
      data-slot="file-upload-item-preview-icon"
      className={clsx(styles.itemPreviewIcon, normalizeClassName(className))}
      {...props}
    />
  );
}

function getFileTypeLabel(file: File) {
  const extension = file.name.split('.').pop();

  return extension ? extension.toUpperCase() : file.type || 'FILE';
}

function isImageFile(file: File) {
  return file.type.startsWith('image/') || /\.(avif|bmp|gif|jpe?g|png|svg|webp)$/i.test(file.name);
}

const FileUploadItemName = forwardRef<
  ComponentRef<typeof FileUploadPrimitive.ItemName>,
  ComponentProps<typeof FileUploadPrimitive.ItemName>
>(function FileUploadItemName({ className, ...props }, ref) {
  return (
    <FileUploadPrimitive.ItemName
      ref={ref}
      data-slot="file-upload-item-name"
      className={clsx(styles.itemName, normalizeClassName(className))}
      {...props}
    />
  );
});

const FileUploadItemSizeText = forwardRef<
  ComponentRef<typeof FileUploadPrimitive.ItemSizeText>,
  ComponentProps<typeof FileUploadPrimitive.ItemSizeText>
>(function FileUploadItemSizeText({ className, ...props }, ref) {
  return (
    <FileUploadPrimitive.ItemSizeText
      ref={ref}
      data-slot="file-upload-item-size-text"
      className={clsx(styles.itemSizeText, normalizeClassName(className))}
      {...props}
    />
  );
});

function FileUploadItemMetadata({
  file,
  className,
  ...props
}: HTMLArkProps<'div'> & { file: File }) {
  return (
    <ark.div
      data-slot="file-upload-item-metadata"
      className={clsx(styles.itemMetadata, normalizeClassName(className))}
      {...props}
    >
      <ark.span>{getFileTypeLabel(file)}</ark.span>
      <FileUploadItemSizeText />
    </ark.div>
  );
}

const FileUploadItemDeleteTrigger = forwardRef<
  ComponentRef<typeof FileUploadPrimitive.ItemDeleteTrigger>,
  ComponentProps<typeof FileUploadPrimitive.ItemDeleteTrigger>
>(function FileUploadItemDeleteTrigger({ className, children, ...props }, ref) {
  return (
    <FileUploadPrimitive.ItemDeleteTrigger
      ref={ref}
      data-slot="file-upload-item-delete-trigger"
      className={clsx(styles.itemDeleteTrigger, normalizeClassName(className))}
      {...props}
    >
      {children ?? <TrashIcon />}
    </FileUploadPrimitive.ItemDeleteTrigger>
  );
});

function FileUploadItems() {
  const { acceptedFiles } = useFileUploadContext();

  return acceptedFiles.map((file) => (
    <FileUploadItem key={`${file.name}-${file.size}`} file={file}>
      {isImageFile(file) ? (
        <FileUploadItemPreview>
          <FileUploadItemPreviewImage />
        </FileUploadItemPreview>
      ) : (
        <FileUploadItemPreview>
          <FileUploadItemPreviewIcon />
        </FileUploadItemPreview>
      )}
      <FileUploadItemName />
      <FileUploadItemMetadata file={file} />
      <FileUploadItemDeleteTrigger aria-label={`Remove ${file.name}`} />
    </FileUploadItem>
  ));
}

const FileUploadClearTrigger = forwardRef<
  ComponentRef<typeof FileUploadPrimitive.ClearTrigger>,
  ComponentProps<typeof FileUploadPrimitive.ClearTrigger>
>(function FileUploadClearTrigger(
  {
    asChild,
    className,
    children,
    'aria-label': ariaLabel,
    'aria-labelledby': ariaLabelledBy,
    ...props
  },
  ref,
) {
  const triggerClassName = clsx(
    styles.clearTrigger,
    children != null && styles.clearTriggerWithContent,
    normalizeClassName(className),
  );

  if (asChild) {
    return (
      <FileUploadPrimitive.ClearTrigger
        ref={ref}
        asChild
        data-slot="file-upload-clear-trigger"
        className={triggerClassName}
        aria-label={ariaLabel}
        aria-labelledby={ariaLabelledBy}
        {...props}
      >
        {children}
      </FileUploadPrimitive.ClearTrigger>
    );
  }

  return (
    <FileUploadPrimitive.ClearTrigger
      ref={ref}
      asChild
      data-slot="file-upload-clear-trigger"
      className={triggerClassName}
      {...props}
    >
      <CloseButton.Root aria-label={ariaLabel} aria-labelledby={ariaLabelledBy}>
        {children ?? <CloseIcon />}
      </CloseButton.Root>
    </FileUploadPrimitive.ClearTrigger>
  );
});

const FileUpload = Object.assign(FileUploadRoot, {
  Root: FileUploadRoot,
  RootProvider: FileUploadRootProvider,
  Context: FileUploadPrimitive.Context,
  Label: FileUploadLabel,
  Dropzone: FileUploadDropzone,
  DropzoneIcon: FileUploadDropzoneIcon,
  Trigger: FileUploadTrigger,
  ItemGroup: FileUploadItemGroup,
  Item: FileUploadItem,
  Items: FileUploadItems,
  ItemPreview: FileUploadItemPreview,
  ItemPreviewImage: FileUploadItemPreviewImage,
  ItemPreviewIcon: FileUploadItemPreviewIcon,
  ItemName: FileUploadItemName,
  ItemMetadata: FileUploadItemMetadata,
  ItemSizeText: FileUploadItemSizeText,
  ItemDeleteTrigger: FileUploadItemDeleteTrigger,
  ClearTrigger: FileUploadClearTrigger,
});

export { FileUpload, useFileUpload, useFileUploadContext };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    gap: var(--file-upload-gap, var(--spacing-3));
    width: var(--file-upload-width, 100%);
    max-width: var(--file-upload-max-width, 28rem);
    color: var(--file-upload-color, var(--color-foreground));

    &[data-disabled] {
      opacity: var(--file-upload-disabled-opacity, var(--opacity-disabled));
    }
  }

  .label {
    color: var(--file-upload-label-color, var(--file-upload-color, var(--color-foreground)));
    font-size: var(--file-upload-label-font-size, var(--text-sm));
    font-weight: var(--file-upload-label-font-weight, var(--weight-medium));
    line-height: var(--file-upload-label-line-height, var(--line-height-text-sm));

    &[data-disabled] {
      opacity: var(--file-upload-disabled-opacity, var(--opacity-disabled));
    }
  }

  .dropzone {
    box-sizing: border-box;
    display: grid;
    width: 100%;
    place-items: center;
    gap: var(--file-upload-dropzone-gap, var(--spacing-3));
    min-height: var(--file-upload-dropzone-min-height, 8rem);
    border: var(--file-upload-dropzone-border-width, var(--border-width-sm)) dashed
      var(--file-upload-dropzone-border-color, var(--color-border));
    border-radius: var(--file-upload-radius, var(--radius-md));
    padding: var(--file-upload-dropzone-padding, var(--spacing-5));
    background-color: var(--file-upload-dropzone-bg, var(--color-background));
    color: var(--file-upload-dropzone-color, var(--color-muted-foreground));
    text-align: center;
    transition:
      border-color var(--file-upload-transition, var(--transition-default)),
      background-color var(--file-upload-transition, var(--transition-default)),
      color var(--file-upload-transition, var(--transition-default)),
      opacity var(--file-upload-transition, var(--transition-default));

    &[data-dragging] {
      border-color: var(--file-upload-dropzone-border-color-dragging, var(--color-primary));
      background-color: var(--file-upload-dropzone-bg-dragging, var(--color-accent));
      color: var(--file-upload-dropzone-color-dragging, var(--color-foreground));
    }

    &[data-invalid] {
      border-color: var(--file-upload-invalid-color, var(--color-destructive));
    }

    &[data-disabled],
    &[data-readonly] {
      cursor: default;
    }
  }

  .dropzoneIcon {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--file-upload-dropzone-icon-box-size, 2.5rem);
    height: var(--file-upload-dropzone-icon-box-size, 2.5rem);
    border: var(--file-upload-dropzone-icon-border-width, var(--border-width-sm)) solid
      var(--file-upload-dropzone-icon-border-color, var(--color-border));
    border-radius: var(--file-upload-dropzone-icon-radius, var(--radius-full));
    background-color: var(--file-upload-dropzone-icon-bg, var(--color-muted));
    color: var(--file-upload-dropzone-icon-color, var(--color-foreground));

    & > svg {
      width: var(--file-upload-dropzone-icon-size, 1rem);
      height: var(--file-upload-dropzone-icon-size, 1rem);
    }
  }

  .trigger {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--file-upload-trigger-gap, var(--button-content-gap, var(--spacing-2)));
    min-height: var(--file-upload-trigger-height, var(--button-size-md, var(--size-md)));
    border: var(
        --file-upload-trigger-border-width,
        var(--button-border-width, var(--border-width-sm))
      )
      solid
      var(
        --file-upload-trigger-border-color,
        var(--button-default-border-color, var(--color-primary))
      );
    border-radius: var(--file-upload-trigger-radius, var(--button-radius, var(--radius-md)));
    padding-inline: var(--file-upload-trigger-padding-x, var(--button-padding-x-md, 1rem));
    background-color: var(--file-upload-trigger-bg, var(--button-default-bg, var(--color-primary)));
    color: var(
      --file-upload-trigger-color,
      var(--button-default-color, var(--color-primary-foreground))
    );
    appearance: none;
    font: inherit;
    font-size: var(--file-upload-trigger-font-size, var(--button-font-size, var(--text-sm)));
    font-weight: var(
      --file-upload-trigger-font-weight,
      var(--button-font-weight, var(--weight-medium))
    );
    line-height: var(
      --file-upload-trigger-line-height,
      var(--button-line-height, var(--line-height-text-sm))
    );
    user-select: none;
    white-space: nowrap;
    cursor: pointer;
    transition:
      border-color
        var(--file-upload-transition, var(--button-transition, var(--transition-default))),
      background-color
        var(--file-upload-transition, var(--button-transition, var(--transition-default))),
      color var(--file-upload-transition, var(--button-transition, var(--transition-default))),
      opacity var(--file-upload-transition, var(--button-transition, var(--transition-default)));

    @media (hover: hover) {
      &:hover:not(:disabled, [data-disabled], [data-readonly]) {
        background-color: var(
          --file-upload-trigger-bg-hover,
          var(--button-default-bg-hover, var(--color-foreground))
        );
      }
    }

    &:focus-visible {
      outline: var(
          --file-upload-focus-ring-width,
          var(--button-focus-ring-width, var(--border-width-md))
        )
        solid var(--file-upload-focus-ring-color, var(--button-focus-ring-color, var(--color-ring)));
      outline-offset: calc(
        var(
            --file-upload-trigger-border-width,
            var(--button-border-width, var(--border-width-sm))
          ) *
          -1
      );
    }

    &[data-invalid] {
      border-color: var(--file-upload-invalid-color, var(--color-destructive));
    }

    &:is(:disabled, [data-disabled], [data-readonly]) {
      pointer-events: none;
      opacity: var(--file-upload-disabled-opacity, var(--opacity-disabled));
      cursor: default;
    }
  }

  .itemGroup {
    display: flex;
    flex-wrap: wrap;
    align-items: flex-start;
    gap: var(--file-upload-item-group-gap, var(--spacing-2));
    width: 100%;
    margin: 0;
    padding: 0;
    list-style: none;

    &:empty {
      display: none;
    }
  }

  .item {
    box-sizing: border-box;
    display: grid;
    grid-template-columns: minmax(0, 1fr) auto;
    align-items: center;
    column-gap: var(--file-upload-item-gap, var(--spacing-3));
    row-gap: var(--file-upload-item-row-gap, var(--spacing-1));
    min-height: var(--file-upload-item-min-height, 2.5rem);
    border: var(--file-upload-item-border-width, var(--border-width-sm)) solid
      var(--file-upload-item-border-color, var(--color-border));
    border-radius: var(--file-upload-item-radius, var(--radius-md));
    padding: var(--file-upload-item-padding-y, var(--spacing-2))
      var(--file-upload-item-padding-x, var(--spacing-3));
    background-color: var(--file-upload-item-bg, var(--color-background));
    color: var(--file-upload-item-color, var(--color-foreground));
    flex: 1 0 100%;

    &[data-type='rejected'] {
      border-color: var(--file-upload-invalid-color, var(--color-destructive));
    }

    &[data-disabled] {
      opacity: var(--file-upload-disabled-opacity, var(--opacity-disabled));
    }

    &:has([data-slot='file-upload-item-preview']) {
      grid-template-columns: auto minmax(0, 1fr) auto;
      min-height: var(--file-upload-item-preview-min-height, 3rem);
      padding-block: var(--file-upload-item-preview-padding-y, var(--spacing-2));
    }
  }

  .itemPreview {
    grid-column: 1;
    grid-row: 1 / span 2;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--file-upload-item-preview-size, var(--spacing-10));
    height: var(--file-upload-item-preview-size, var(--spacing-10));
    border-radius: var(--file-upload-item-preview-radius, var(--radius-sm));
    background-color: var(--file-upload-item-preview-bg, var(--color-muted));
    color: var(--file-upload-item-preview-color, var(--color-muted-foreground));
    overflow: hidden;
  }

  .itemPreviewImage {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  .itemPreviewIcon {
    width: 1rem;
    height: 1rem;
  }

  .itemMetadata {
    grid-column: 1;
    display: flex;
    align-items: center;
    gap: var(--file-upload-item-row-gap, var(--spacing-1));
    color: var(--file-upload-item-size-color, var(--color-muted-foreground));
    font-size: var(--file-upload-item-size-font-size, var(--text-xs));
    line-height: var(--file-upload-item-size-line-height, var(--line-height-text-xs));

    & > [data-slot='file-upload-item-size-text']::before {
      margin-inline-end: var(--file-upload-item-row-gap, var(--spacing-1));
      content: '·';
    }
  }

  .itemName {
    grid-column: 1;
    min-width: 0;
    color: var(--file-upload-item-name-color, currentColor);
    font-size: var(--file-upload-item-name-font-size, var(--text-sm));
    font-weight: var(--file-upload-item-name-font-weight, var(--weight-medium));
    line-height: var(--file-upload-item-name-line-height, var(--line-height-text-sm));
    display: -webkit-box;
    overflow: hidden;
    -webkit-box-orient: vertical;
    -webkit-line-clamp: 1;
    line-clamp: 1;
  }

  .item:has([data-slot='file-upload-item-preview']) .itemName {
    grid-column: 2;
  }

  .itemSizeText {
    grid-column: 1;
    color: var(--file-upload-item-size-color, var(--color-muted-foreground));
    font-size: var(--file-upload-item-size-font-size, var(--text-xs));
    line-height: var(--file-upload-item-size-line-height, var(--line-height-text-xs));
  }

  .item:has([data-slot='file-upload-item-preview']) .itemSizeText {
    grid-column: 2;
  }

  .item:has([data-slot='file-upload-item-preview']) .itemMetadata {
    grid-column: 2;
  }

  .itemDeleteTrigger {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--file-upload-action-size, 2rem);
    height: var(--file-upload-action-size, 2rem);
    border: 0;
    border-radius: var(--file-upload-action-radius, var(--radius-sm));
    padding: 0;
    background-color: var(--file-upload-action-bg, transparent);
    color: var(--file-upload-action-color, var(--color-muted-foreground));
    appearance: none;
    cursor: pointer;
    transition:
      background-color var(--file-upload-transition, var(--transition-default)),
      color var(--file-upload-transition, var(--transition-default)),
      opacity var(--file-upload-transition, var(--transition-default));

    & > svg {
      width: var(--file-upload-action-icon-size, 1rem);
      height: var(--file-upload-action-icon-size, 1rem);
    }

    @media (hover: hover) {
      &:hover:not(:disabled, [data-disabled], [data-readonly]) {
        background-color: var(--file-upload-action-bg-hover, var(--color-muted));
        color: var(--file-upload-action-color-hover, var(--color-foreground));
      }
    }

    &:focus-visible {
      outline: var(--file-upload-focus-ring-width, var(--border-width-md)) solid
        var(--file-upload-focus-ring-color, var(--color-ring));
      outline-offset: var(--file-upload-focus-ring-offset, var(--border-width-sm));
    }

    &:is(:disabled, [data-disabled], [data-readonly]) {
      pointer-events: none;
      opacity: var(--file-upload-disabled-opacity, var(--opacity-disabled));
      cursor: default;
    }
  }

  .itemDeleteTrigger {
    grid-column: 2;
    grid-row: 1;
    justify-self: end;
  }

  .item:has([data-slot='file-upload-item-size-text']) .itemDeleteTrigger,
  .item:has([data-slot='file-upload-item-preview']) .itemDeleteTrigger {
    grid-row: 1 / span 2;
  }

  .item:has([data-slot='file-upload-item-preview']) .itemDeleteTrigger {
    grid-column: 3;
  }

  .item:has([data-slot='file-upload-item-preview-image']) {
    flex: 0 1 min(100%, 10rem);
    grid-template-columns: minmax(0, 1fr) auto;
    grid-template-rows: auto auto auto;
    align-items: start;
    min-height: 0;
  }

  .item:has([data-slot='file-upload-item-preview-image']) .itemPreview {
    grid-column: 1 / -1;
    grid-row: 1;
    width: 100%;
    height: auto;
    aspect-ratio: 1;
  }

  .item:has([data-slot='file-upload-item-preview-image']) .itemName {
    grid-column: 1;
    grid-row: 2;
    align-self: end;
  }

  .item:has([data-slot='file-upload-item-preview-image']) .itemMetadata {
    grid-column: 1;
    grid-row: 3;
  }

  .item:has([data-slot='file-upload-item-preview-image']) .itemDeleteTrigger {
    grid-column: 2;
    grid-row: 2 / span 2;
    align-self: center;
  }

  .clearTrigger {
    align-self: flex-start;
    --close-button-size: var(--file-upload-action-size, 2rem);
    --close-button-radius: var(--file-upload-action-radius, var(--radius-sm));
    --close-button-bg: var(--file-upload-action-bg, transparent);
    --close-button-bg-hover: var(--file-upload-action-bg-hover, var(--color-muted));
    --close-button-color: var(--file-upload-clear-trigger-color, var(--color-muted-foreground));
    --close-button-color-hover: var(--file-upload-action-color-hover, var(--color-foreground));
    --close-button-icon-size: var(--file-upload-action-icon-size, 1rem);
    --close-button-transition: var(--file-upload-transition, var(--transition-default));
    --close-button-focus-ring-width: var(--file-upload-focus-ring-width, var(--border-width-md));
    --close-button-focus-ring-color: var(--file-upload-focus-ring-color, var(--color-ring));
    --close-button-focus-ring-offset: var(--file-upload-focus-ring-offset, var(--border-width-sm));
    --close-button-disabled-opacity: var(--file-upload-disabled-opacity, var(--opacity-disabled));
  }

  .clearTriggerWithContent {
    gap: var(--file-upload-clear-trigger-gap, var(--spacing-2));
    width: auto;
    padding-inline: var(--file-upload-clear-trigger-padding-x, var(--spacing-2));
    font: inherit;
    font-size: var(--file-upload-clear-trigger-font-size, var(--text-sm));
    line-height: var(--file-upload-clear-trigger-line-height, var(--line-height-text-sm));
  }

  .clearTrigger[data-readonly] {
    pointer-events: none;
    opacity: var(--file-upload-disabled-opacity, var(--opacity-disabled));
  }
}
